#!/usr/bin/env node
// AccentOS Quote Generator v2 — surgical patch
// Run from: /workspaces/accent-os/
const fs = require('fs'), path = require('path');

const REPLACEMENT_B64 = "";
const replacement = Buffer.from(REPLACEMENT_B64, 'base64').toString('utf8');

const indexPath = path.join(process.cwd(), 'index.html');
if (!fs.existsSync(indexPath)) { console.error('Run from /workspaces/accent-os/'); process.exit(1); }

const src = fs.readFileSync(indexPath, 'utf8');
const startIdx = src.indexOf('let QUOTES=[],QUOTE_ID=1,CQ=null,LI=[];');
const endIdx = src.indexOf('\n// ══════════════════════════════════════════════════════════\n// ── KNOWLEDGE ENGINE', startIdx);
if (startIdx===-1||endIdx===-1) { console.error('Markers not found'); process.exit(1); }

console.log('Replacing chars', startIdx, '→', endIdx);
const newSrc = src.slice(0, startIdx) + replacement + '\n' + src.slice(endIdx);

const checks = ['aiParseNotes','calcTrackHardware','exportQuoteCSV','renderLI','openTrackCalc','approveAllRows'];
let ok = true;
checks.forEach(fn => {
  if (newSrc.indexOf(fn)===-1) { console.error('MISSING:', fn); ok=false; }
  else console.log('✓', fn);
});
if (!ok) process.exit(1);

fs.writeFileSync(indexPath, newSrc, 'utf8');
console.log('\n✓ Patched —', newSrc.length, 'bytes');
